from ag2 import GroupChat

def cost_turn_detector(messages, agent):
    if len(messages) > 50:
        return {
            'alert': 'HIGH_COST_SPIRAL',
            'tokens_used': sum(len(str(m.content)) for m in messages[-10:]),
            'turn_count': len(messages),
            'agents_involved': len(set(m.sender for m in messages))
        }
    return None

def speaker_bias_detector(messages, agent):
    speakers = [m.sender for m in messages[-20:]]
    counts = {s: speakers.count(s) for s in set(speakers)}
    max_dominance = max(counts.values()) / len(speakers)

    if max_dominance > 0.7:
        return {
            'alert': 'SPEAKER_BIAS',
            'dominant_agent': max(counts, key=counts.get),
            'dominance_ratio': max_dominance,
            'token_inefficiency': '80%+ budget to single agent'
        }
    return None

