from ag2 import GroupChat, on_message

@on_message
async def cost_termination_hook(message, chat):
    if len(chat.messages) >= 30:
        await chat.terminate(
            reason="COST_LIMIT_EXCEEDED",
            final_summary=chat.messages[-3:]
        )
        return False  # Stop message processing
    return True
